UPDATE `petlog`.`feed`
SET like_count = like_count + 1
WHERE id = #{feedId}

UPDATE `petlog`.`feed`
SET like_count = IF(like_count > 0, like_count - 1, 0)
WHERE id = #{feedId}

UPDATE `petlog`.`feed`
SET comment_count = comment_count + #{count}
WHERE id = #{feedId}

mapper.select:
SELECT EXISTS(
    SELECT 1
    FROM `petlog`.`feed`
    WHERE id = #{feedId}
)
